CREATE TYPE "AppointmentStatus" AS ENUM ('PENDING','CONFIRMED','REFUSED','CANCELLED','COMPLETED','ARCHIVED');
CREATE TABLE "Service" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"slug" TEXT NOT NULL,"description" TEXT NOT NULL,"duration" TEXT NOT NULL,"price" TEXT,"image" TEXT,"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Service_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Hairstyle" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"slug" TEXT NOT NULL,"category" TEXT NOT NULL,"description" TEXT NOT NULL,"duration" TEXT NOT NULL,"price" TEXT,"mainImage" TEXT NOT NULL,"galleryImages" TEXT[],"isFeatured" BOOLEAN NOT NULL DEFAULT false,"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Hairstyle_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Appointment" ("id" TEXT NOT NULL,"reference" TEXT NOT NULL,"customerName" TEXT NOT NULL,"phone" TEXT NOT NULL,"whatsapp" TEXT NOT NULL,"email" TEXT,"appointmentDate" TIMESTAMP(3) NOT NULL,"appointmentTime" TEXT NOT NULL,"location" TEXT NOT NULL,"appointmentType" TEXT NOT NULL,"preferredContactMethod" TEXT NOT NULL,"message" TEXT,"status" "AppointmentStatus" NOT NULL DEFAULT 'PENDING',"notificationErrors" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,"serviceId" TEXT NOT NULL,"hairstyleId" TEXT,CONSTRAINT "Appointment_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "Service_slug_key" ON "Service"("slug");CREATE UNIQUE INDEX "Hairstyle_slug_key" ON "Hairstyle"("slug");CREATE UNIQUE INDEX "Appointment_reference_key" ON "Appointment"("reference");CREATE UNIQUE INDEX "Appointment_appointmentDate_appointmentTime_key" ON "Appointment"("appointmentDate","appointmentTime");CREATE INDEX "Appointment_status_appointmentDate_idx" ON "Appointment"("status","appointmentDate");
ALTER TABLE "Appointment" ADD CONSTRAINT "Appointment_serviceId_fkey" FOREIGN KEY ("serviceId") REFERENCES "Service"("id") ON DELETE RESTRICT ON UPDATE CASCADE;ALTER TABLE "Appointment" ADD CONSTRAINT "Appointment_hairstyleId_fkey" FOREIGN KEY ("hairstyleId") REFERENCES "Hairstyle"("id") ON DELETE SET NULL ON UPDATE CASCADE;
